def test_retry_then_success(monkeypatch):
    monkeypatch.delenv("HCGRC_DISABLE_REASONING", raising=False)
    monkeypatch.setattr(rc.time, "sleep", lambda *_: None)
    calls = {"n": 0}

    def flaky(*args, **kwargs):
        calls["n"] += 1
        if calls["n"] < 2:
            raise ReasoningError("transient")
        return "ok", {"model": "m"}
